      const parts = [];
      if (entry.harvest > 0) parts.push(`P:${entry.harvest}kg`);
      if (entry.medium > 0) parts.push(`S:${entry.medium}kg`);
      if (entry.small > 0) parts.push(`K:${entry.small}kg`);
